package com.nstut.buildinggadgetsextra.client;import com.direwolf20.buildinggadgets.client.screen.components.GuiIconActionable;import com.mojang.blaze3d.matrix.MatrixStack;import com.mojang.blaze3d.systems.RenderSystem;import com.nstut.buildinggadgetsextra.common.ExtraConstants;import net.minecraft.client.Minecraft;import net.minecraft.util.ResourceLocation;import net.minecraft.util.text.ITextComponent;
public final class StructureLibraryButton extends GuiIconActionable{private static final ResourceLocation ICON=new ResourceLocation(ExtraConstants.MOD_ID,"textures/gui/setting/library.png");public StructureLibraryButton(int x,int y,ITextComponent tip,Runnable action){super(x,y,"buildinggadgetsextra_placeholder",tip,false,s->{if(s)action.run();return false;});width=24;height=24;}@Override public void render(MatrixStack stack,int mx,int my,float p){if(!visible)return;Minecraft m=Minecraft.getInstance();fill(stack,x,y,x+width,y+height,0x32FFFFFF);RenderSystem.enableBlend();m.getTextureManager().bind(ICON);blit(stack,x,y,width,height,0,0,44,44,44,44);RenderSystem.disableBlend();if(mx>=x&&my>=y&&mx<x+width&&my<y+height){String t=getMessage().getString();int tx=mx>m.getWindow().getGuiScaledWidth()/2?mx+2:mx-m.font.width(t);drawString(stack,m.font,t,tx,my-10,0xFFFFFFFF);}}}
